/// Content block in a response message.
///
/// Response content blocks represent different types of content
/// generated by the model. Unknown types are preserved as
/// [UnknownContentBlock] for forward compatibility.
sealed class ContentBlock {
  const ContentBlock();

  /// Creates a [ContentBlock] from JSON.
  factory ContentBlock.fromJson(Map<String, dynamic> json) {
    final type = json['type'] as String;
    return switch (type) {
      'text' => TextBlock.fromJson(json),
      'thinking' => ThinkingBlock.fromJson(json),
      'redacted_thinking' => RedactedThinkingBlock.fromJson(json),
      'tool_use' => ToolUseBlock.fromJson(json),
      'server_tool_use' => ServerToolUseBlock.fromJson(json),
      'web_search_tool_result' => WebSearchToolResultBlock.fromJson(json),
      'web_fetch_tool_result' => WebFetchToolResultBlock.fromJson(json),
      'code_execution_tool_result' => CodeExecutionToolResultBlock.fromJson(
        json,
      ),
      'bash_code_execution_tool_result' =>
        BashCodeExecutionToolResultBlock.fromJson(json),
      'text_editor_code_execution_tool_result' =>
        TextEditorCodeExecutionToolResultBlock.fromJson(json),
      'tool_search_tool_result' => ToolSearchToolResultBlock.fromJson(json),
      'container_upload' => ContainerUploadBlock.fromJson(json),
      'compaction' => CompactionBlock.fromJson(json),
      'mcp_tool_use' => MCPToolUseBlock.fromJson(json),
      'mcp_tool_result' => MCPToolResultBlock.fromJson(json),
      'advisor_tool_result' => AdvisorToolResultBlock.fromJson(json),
      _ => UnknownContentBlock.fromJson(json),
    };
  }

  /// Converts to JSON.
  Map<String, dynamic> toJson();
}

/// Text content block in a response.
@immutable
class TextBlock extends ContentBlock {
  /// The text content.
  final String text;

  /// Citations supporting this text block.
  final List<Citation>? citations;

  /// Creates a [TextBlock].
  const TextBlock({required this.text, this.citations});

  /// Creates a [TextBlock] from JSON.
  factory TextBlock.fromJson(Map<String, dynamic> json) {
    return TextBlock(
      text: json['text'] as String,
      citations: (json['citations'] as List?)
          ?.map((e) => Citation.fromJson(e as Map<String, dynamic>))
          .toList(),
    );
  }

  @override
  Map<String, dynamic> toJson() => {
    'type': 'text',
    'text': text,
    if (citations != null)
      'citations': citations!.map((e) => e.toJson()).toList(),
  };

  /// Creates a copy with replaced values.
  TextBlock copyWith({String? text, Object? citations = unsetCopyWithValue}) {
    return TextBlock(
      text: text ?? this.text,
      citations: citations == unsetCopyWithValue
          ? this.citations
          : citations as List<Citation>?,
    );
  }

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is TextBlock &&
          runtimeType == other.runtimeType &&
          text == other.text &&
          listsEqual(citations, other.citations);

  @override
  int get hashCode => Object.hash(text, listHash(citations));

  @override
  String toString() =>
      'TextBlock(text: [${text.length} chars], citations: $citations)';
}

