/// Compaction content block (beta).
///
/// Returned when server-side compaction is triggered. Can be round-tripped
/// back to subsequent requests to preserve compacted context.
@immutable
class CompactionBlock extends ContentBlock {
  /// Summary content for compacted context.
  ///
  /// When `null`, compaction failed and the block is a no-op if round-tripped.
  final String? content;

  /// Encrypted compaction payload for server-side context restoration.
  final String? encryptedContent;

  /// Creates a [CompactionBlock].
  const CompactionBlock({required this.content, this.encryptedContent});

  /// Creates a [CompactionBlock] from JSON.
  factory CompactionBlock.fromJson(Map<String, dynamic> json) {
    return CompactionBlock(
      content: json['content'] as String?,
      encryptedContent: json['encrypted_content'] as String?,
    );
  }

  @override
  Map<String, dynamic> toJson() => {
    'type': 'compaction',
    'content': content,
    'encrypted_content': encryptedContent,
  };

  /// Creates a copy with replaced values.
  CompactionBlock copyWith({
    Object? content = unsetCopyWithValue,
    Object? encryptedContent = unsetCopyWithValue,
  }) {
    return CompactionBlock(
      content: content == unsetCopyWithValue
          ? this.content
          : content as String?,
      encryptedContent: encryptedContent == unsetCopyWithValue
          ? this.encryptedContent
          : encryptedContent as String?,
    );
  }

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is CompactionBlock &&
          runtimeType == other.runtimeType &&
          content == other.content &&
          encryptedContent == other.encryptedContent;

  @override
  int get hashCode => Object.hash(content, encryptedContent);

  @override
  String toString() =>
      'CompactionBlock(content: $content, '
      'encryptedContent: ${encryptedContent == null ? 'null' : '[${encryptedContent!.length} chars]'})';
}

/// Web search result content.
sealed class WebSearchResult {
  const WebSearchResult();

  /// Creates a [WebSearchResult] from JSON.
  ///
  /// The [json] parameter accepts either a `List` (array of search result
  /// items for the success case) or a `Map` (error object with
  /// `type: "web_search_tool_result_error"`).
  factory WebSearchResult.fromJson(Object json) {
    if (json is List) {
      return WebSearchResultSuccess.fromJson(json);
    }
    if (json is Map) {
      final map = json.cast<String, dynamic>();
      final type = map['type'];
      if (type is String) {
        if (type == 'web_search_tool_result_error') {
          return WebSearchResultError.fromJson(map);
        }
        throw FormatException('Unknown WebSearchResult type: $type');
      }
      throw const FormatException(
        'Invalid WebSearchResult: "type" must be a string',
      );
    }
    throw FormatException(
      'Expected List or Map for WebSearchResult, got ${json.runtimeType}',
    );
  }

  /// Converts to JSON.
  Object toJson();
}

/// Successful web search result.
@immutable
class WebSearchResultSuccess extends WebSearchResult {
  /// The search results.
  final List<WebSearchResultItem> results;

  /// Creates a [WebSearchResultSuccess].
  const WebSearchResultSuccess({required this.results});

  /// Creates a [WebSearchResultSuccess] from a JSON array of result items.
  factory WebSearchResultSuccess.fromJson(List<dynamic> json) {
    return WebSearchResultSuccess(
      results: json
          .map((e) => WebSearchResultItem.fromJson(e as Map<String, dynamic>))
          .toList(),
    );
  }

  @override
  List<Map<String, dynamic>> toJson() =>
      results.map((e) => e.toJson()).toList();

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is WebSearchResultSuccess &&
          runtimeType == other.runtimeType &&
          listsEqual(results, other.results);

  @override
  int get hashCode => listHash(results);

  @override
  String toString() => 'WebSearchResultSuccess(results: $results)';
}

/// A single web search result item.
@immutable
class WebSearchResultItem {
  /// URL of the search result.
  final String url;

