    'input': input,
  };

  /// Creates a copy with replaced values.
  MCPToolUseBlock copyWith({
    String? id,
    String? name,
    String? serverName,
    Map<String, dynamic>? input,
  }) {
    return MCPToolUseBlock(
      id: id ?? this.id,
      name: name ?? this.name,
      serverName: serverName ?? this.serverName,
      input: input ?? this.input,
